function.body:
TYPE RECORD IS REF CURSOR;
  Cur_Parameter RECORD;
  Cur_PaymentMethod RECORD;
  Cur_ClousureLines RECORD;
  Cur_AccountTransaction RECORD;
  Cur_ValidationPayments RECORD;


  v_User_ID VARCHAR2(32) ;
  v_ClosingDate DATE;
  v_ResultStr VARCHAR2(2000) := '';
  v_Concept_ID VARCHAR2(32);
  v_LoadLines VARCHAR2(60);
  v_RecordId VARCHAR2(32);
  v_OrganizationId VARCHAR2(32);
  v_Contador NUMBER:=0; 
  v_TotalIncome NUMBER:=0; 
  v_TotalExpenses NUMBER:=0; 
  v_Docstatus VARCHAR2(60); 
  v_PeriodStatus  VARCHAR(60);--OBTG:VARCHAR2--
  v_ContadorLineas NUMBER:=0;
  v_TotalIncome2 NUMBER:=0; 
  v_TotalExpenses2 NUMBER:=0; 
  v_module NUMBER:=0; 
  v_Grandtotal NUMBER:=0; 
  v_type_payment  VARCHAR2(60);
  v_id  VARCHAR2(32);
  v_doctypesales VARCHAR2(32);
  v_doctypecreditnote VARCHAR2(32);
  v_total NUMBER:=0; 
  v_amount_aux NUMBER:=0; 
  v_amount_pay NUMBER:=0; 
  v_totalsales NUMBER:=0; 
  v_creditnotes NUMBER:=0;   
  v_setup_id VARCHAR2(32);
  v_preference VARCHAR2(60);

BEGIN

  --  Update AD_PInstance
  DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || PInstance_ID) ;
  v_ResultStr := 'PInstanceNotFound';
  AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'Y', NULL, NULL) ;

  BEGIN --BODY

-- GET:    
    FOR Cur_Parameter IN
      (SELECT i.Record_ID,
        p.ParameterName,
        p.P_String,
        p.P_Number,
        p.P_Date,
        p.AD_Client_ID,
        p.AD_Org_ID,
        p.CreatedBy,
        i.ad_user_id        
      FROM AD_PInstance i
      LEFT JOIN AD_PInstance_Para p
           ON i.AD_PInstance_ID = p.AD_PInstance_ID
      WHERE i.AD_PInstance_ID = pinstance_id
      ORDER BY p.SeqNo
      )
    LOOP
        v_RecordId := Cur_Parameter.Record_ID;
        v_User_ID  := Cur_Parameter.ad_user_id;        
    END LOOP;  

        SELECT record,ad_org_id,closingdate,docstatus,sccc_setup_id INTO v_LoadLines,v_OrganizationId,v_ClosingDate,v_Docstatus,v_setup_id FROM sccc_cash_clousure where sccc_cash_clousure_id= v_RecordId;

	 --COMPROBAR EXISTENCIA MÓDULO ec.com.sidesoft.custom.closecash.advanced
	SELECT 
	COALESCE((SELECT COUNT(*) AS CONTAR FROM AD_MODULE WHERE JAVAPACKAGE = 'ec.com.sidesoft.custom.closecash.advanced'),0)
	INTO v_Module
	FROM DUAL;

	--SE COMPRUEBA SI EL PERÍODO ESTÁ CERRADO
	SELECT openclose INTO v_PeriodStatus FROM c_period WHERE v_ClosingDate>=startdate AND v_ClosingDate <= enddate;
	IF ( v_PeriodStatus='O')THEN
	 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@PeriodNotAvailable@') ;
		RETURN;
	END IF;

    IF(v_LoadLines ='SCCC_RE') THEN

	-- Validación para pagos detallados
	For Cur_ValidationPayments in (
		Select SUM(COALESCE(spd.amount,0)) as "amount_detail"
			, COALESCE(ccl.amount,0) as "amount_total"
			, pm.name as "metodo_pago"
		From sccc_cash_clousureline ccl
			join fin_paymentmethod pm on pm.fin_paymentmethod_id = ccl.fin_paymentmethod_id
			Join sscrcc_payment_detailed spd on spd.sccc_cash_clousureline_id = ccl.sccc_cash_clousureline_id
		Where ccl.sccc_cash_clousure_id = v_RecordId
			And EXISTS (
				Select 1 
				From sccc_cash_clousure sx 
					Join sccc_setup st on st.ad_org_id  = sx.ad_org_id  
					Join sccc_payment_method spm on spm.sccc_setup_id = st.sccc_setup_id 
						And pm.fin_paymentmethod_id = spm.fin_paymentmethod_id
						And spm.em_sscrcc_detailed = 'Y'
				Where sx.sccc_cash_clousure_id = ccl.sccc_cash_clousure_id
			)
		Group By ccl.fin_paymentmethod_id, pm.name,ccl.amount
	)Loop
		If(Cur_ValidationPayments.amount_detail <> Cur_ValidationPayments.amount_total)Then
			RAISE_APPLICATION_ERROR(-20000, 'El detalle metodo de pago '||Cur_ValidationPayments.metodo_pago||' tiene diferencia.');
		End If;
	END LOOP; -- End Cur_AccountTransaction
	-- Fin Validación para pagos detallados

	--Start Proceso 1
	Select SUM(Case When type_of_operation = 'BPD' Then--Cobro 
				coalesce(scie.deposit_amount,0)
		When type_of_operation = 'BPW' Then--Pago
				coalesce(scie.refund_amount,0)*-1
		ELSE 0 END) as "amount"
		Into v_amount_aux
	From ssccso_cash_inc_exp scie
	Where scie.sccc_cash_clousure_id = v_RecordId;
	-- End Proceso 1

	-- START Proceso 2
	  Select SUM(COALESCE(amount, 0))
		Into v_amount_pay
	  From fin_payment fp     
	  Where fp.isreceipt = 'Y' 
		And fp.createdby = v_User_ID
		And fp.ad_org_id = v_OrganizationId
		And TO_DATE(fp.paymentdate,'dd-mm-yyyy')=TO_DATE(v_ClosingDate,'dd-mm-yyyy')
		And EXISTS (Select 1
			From ssccso_type_of_document sstd 
				Join sccc_setup sss on sss.sccc_setup_id = sstd.sccc_setup_id
			Where sss.ad_org_id = v_OrganizationId
				And c_doctype_id = fp.c_doctype_id);
	-- End Proceso 2

	--Consulta lineas de cierre de caja
	SELECT count(*) INTO v_ContadorLineas FROM sccc_cash_clousureline WHERE sccc_cash_clousure_ID= v_RecordId ;
	IF (v_ContadorLineas=0) THEN  
	 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@SCCC_LINES_NOT_FOUND@') ;
		RETURN;
	END IF;

	-- SUMA Ingresos
	SELECT coalesce(sum(amount),0) INTO v_TotalIncome FROM sccc_cash_clousureline 
	WHERE sccc_cash_clousure_ID= v_RecordId AND Typeaccount='INC';
	-- SUMA EGRESOS
	SELECT coalesce(sum(abs(amount)),0) INTO v_TotalExpenses FROM sccc_cash_clousureline
	WHERE sccc_cash_clousure_ID= v_RecordId AND Typeaccount='EXP';

	IF (v_Module>0) THEN
		EXECUTE IMMEDIATE 'SELECT coalesce(sum(amount),0) FROM scca_cash_clousureline2 
		WHERE sccc_cash_clousure_ID='''|| v_RecordId ||''' AND Typeaccount=''INC'' ' INTO v_TotalIncome2; 

		EXECUTE IMMEDIATE 'SELECT coalesce(sum(abs(amount)),0) FROM scca_cash_clousureline2
		WHERE sccc_cash_clousure_ID='''|| v_RecordId ||''' AND Typeaccount=''EXP'' ' INTO v_TotalExpenses2; 
	END IF;

	v_Grandtotal:= COALESCE(v_TotalIncome,0)+COALESCE(v_TotalIncome2,0)-COALESCE(v_TotalExpenses,0)-COALESCE(v_TotalExpenses2,0);

        IF (v_Grandtotal=0) THEN

		DBMS_OUTPUT.PUT_LINE('@SCCC_TOTAL_ZERO@') ;
	 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@SCCC_TOTAL_ZERO@') ;
		RETURN;

	END IF;

	SELECT COALESCE(( 	SELECT value
				FROM ad_preference
				WHERE property = 'Sccc_CloseCashDoctype'
				AND created = ( SELECT MAX(created) FROM ad_preference 
				WHERE property = 'Sccc_CloseCashDoctype')
			),'N')
	INTO v_preference
	FROM DUAL;      

	IF (v_preference='N') THEN
		SELECT 
		SUM(
		CASE WHEN dt.isreversal='Y' OR dt.isreturn='Y' THEN
			abs(ci.totalpaid)*-1
		ELSE
			ci.totalpaid
		END
		) INTO v_total
		FROM c_invoice ci
		LEFT JOIN c_doctype dt ON ci.c_doctype_id = dt.c_doctype_id
		WHERE ci.docstatus='CO' AND ci.issotrx='Y' 
			And ci.createdby = v_User_ID
			AND ci.ad_org_id = v_OrganizationId 
			AND TO_DATE(ci.dateinvoiced,'dd-mm-yyyy')=TO_DATE(v_ClosingDate,'dd-mm-yyyy');
		--OBTENER VALOR DE NOTAS DE CREDITO
		  SELECT 
			SUM(abs(ci.totalpaid)) 
			INTO v_creditnotes
		  FROM c_invoice ci
			Left Join c_doctype dt On ci.c_doctype_id = dt.c_doctype_id
		  Where ci.docstatus='CO' And ci.issotrx='Y' 
			And ci.createdby = v_User_ID
			And ci.ad_org_id=v_OrganizationId 
			And TO_DATE(ci.dateinvoiced,'dd-mm-yyyy')=TO_DATE(v_ClosingDate,'dd-mm-yyyy')
			And dt.isreversal='Y' OR dt.isreturn='Y';

		--OBTENER VALOR DE COBROS RELACIONADOS A FACTURAS 
		  Select COALESCE(fpd.amount ,0)
			INTO v_totalsales
		  From fin_payment fp
			Join fin_payment_detail fpd on fpd.fin_payment_id =fp.fin_payment_id
			Join fin_payment_scheduledetail fpsd on fpsd.fin_payment_detail_id = fpd.fin_payment_detail_id
			Join fin_payment_schedule fps on fps.fin_payment_schedule_id = fpsd.fin_payment_schedule_invoice
		  Where status <> 'RPVOID'
			And TO_DATE(fp.paymentdate,'dd-mm-yyyy') = TO_DATE(v_ClosingDate,'dd-mm-yyyy')
			And fp.createdby = v_User_ID
			And fp.ad_org_id = v_OrganizationId
			And EXISTS (Select 1 
				From c_invoice ci
					Join c_doctype dt on ci.c_doctype_id = dt.c_doctype_id
				WHERE fps.c_invoice_id =ci.c_invoice_id
					And ci.docstatus = 'CO' 
					And ci.issotrx = 'Y' 
					And dt.isreversal<>'Y' 
					And dt.isreturn<>'Y'
					And ci.createdby = v_User_ID
					And ci.ad_org_id = v_OrganizationId);

		  v_total := ABS(COALESCE(v_totalsales,0))-ABS(COALESCE(v_creditnotes,0));
	ELSE

		IF(v_setup_id IS NULL) THEN
		 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@Sccc_SetupNotSet@') ;
			RETURN;			
		END IF;

		SELECT c_doctype_sales_id, c_doctype_credit_notes_id
			INTO v_doctypesales, v_doctypecreditnote
		FROM sccc_setup 
		WHERE sccc_setup_id = v_setup_id;

		IF (v_doctypesales IS NULL OR v_doctypecreditnote IS NULL) THEN
		 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, '@Sccc_DocTypeNull@') ;
			RETURN;
		END IF;		

		Select SUM(COALESCE(fpd.amount ,0))
				INTO v_totalsales
		From fin_payment fp
			Join fin_payment_detail fpd on fpd.fin_payment_id =fp.fin_payment_id
			Join fin_payment_scheduledetail fpsd on fpsd.fin_payment_detail_id = fpd.fin_payment_detail_id
			Join fin_payment_schedule fps on fps.fin_payment_schedule_id = fpsd.fin_payment_schedule_invoice
		Where fp.status <> 'RPVOID'
			And fp.createdby = v_User_ID
			And fp.ad_org_id = v_OrganizationId
			And TO_DATE(fp.paymentdate,'dd-mm-yyyy') = TO_DATE(v_ClosingDate,'dd-mm-yyyy')
			And EXISTS (Select 1 
				From c_invoice ci
				WHERE fps.c_invoice_id =ci.c_invoice_id
					And ci.docstatus = 'CO' 
					And ci.issotrx = 'Y' 
					And ci.createdby = v_User_ID
					And ci.ad_org_id = v_OrganizationId
					AND ci.c_doctype_id = v_doctypesales);

		SELECT sum(totalpaid) INTO v_creditnotes
		FROM c_invoice WHERE TO_DATE(dateinvoiced,'dd-mm-yyyy')=TO_DATE(v_ClosingDate,'dd-mm-yyyy') AND c_doctype_id = v_doctypecreditnote
		And createdby = v_User_ID
		And ad_org_id = v_OrganizationId
		AND docstatus='CO' AND issotrx='Y' ;	

		v_total := ABS(COALESCE(v_totalsales,0))-ABS(COALESCE(v_creditnotes,0));

	END IF;

	UPDATE sccc_cash_clousure SET docstatus='SCCC_RG' WHERE sccc_cash_clousure_ID= v_RecordId;
	v_total  := v_total + COALESCE(v_amount_aux, 0) + COALESCE(v_amount_pay, 0);
	UPDATE sccc_cash_clousure SET 
		  totalincome= v_TotalIncome + v_TotalIncome2
		, totalexpenses= v_TotalExpenses + v_TotalExpenses2 
		, totalsales = COALESCE(v_total,0)
		, difference=COALESCE(v_total,0)-COALESCE(v_Grandtotal,0)
	 WHERE sccc_cash_clousure_ID= v_RecordId ;

	UPDATE sccc_cash_clousure SET record='RE' WHERE sccc_cash_clousure_ID= v_RecordId;

    ELSE
	    IF(v_LoadLines ='RE' AND v_Docstatus='SCCC_RG') THEN
		UPDATE sccc_cash_clousure SET docstatus='DR',totalincome=0,totalexpenses=0,totalsales=0,difference=0 WHERE sccc_cash_clousure_ID= v_RecordId;
		UPDATE sccc_cash_clousure SET record='SCCC_RE' WHERE sccc_cash_clousure_ID= v_RecordId;
	    END IF;
    END IF; 
	-- Actualizar Lote
	FOR Cur_ClousureLines IN (
		SELECT  a.em_scca_lot ,b.fin_paymentmethod_id
		FROM sccc_cash_clousureline a
			left join fin_paymentmethod b on b.fin_paymentmethod_id=a.fin_paymentmethod_id 
		WHERE b.EM_Scca_Type_Payment = 'CA'
			And a.sccc_cash_clousure_id =v_RecordId 
		ORDER BY a.order_number
	)LOOP
		For Cur_AccountTransaction in (
			Select ft.fin_payment_id
			From fin_finacc_transaction ft
				join fin_payment fp on fp.fin_payment_id  =ft.fin_payment_id 
			where fp.fin_paymentmethod_id = Cur_ClousureLines.fin_paymentmethod_id
				And ft.statementdate  = v_ClosingDate
				And ft.em_sccc_iscashclousure <>'Y'
				And ft.em_sccc_cash_clousure_id is null
			Group By ft.fin_payment_id
		)Loop
			update fin_payment set description = coalesce(description,'')||'
Lote N° '||COALESCE(Cur_ClousureLines.em_scca_lot,'') Where fin_payment_id = Cur_AccountTransaction.fin_payment_id ;

		END LOOP; -- End Cur_AccountTransaction
	END LOOP; -- End Cur_ClousureLines
	-- Fin Actualizar Lote

    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 1, '@Success@') ;
    RETURN;

  END; --BODY
  EXCEPTION
  WHEN OTHERS THEN
    v_ResultStr:= '@ERROR=' || SQLERRM;
    DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
    RETURN;
END SSCCSO_RECORD
